    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0xFBED1818ECB71505ULL + 0xF888B4EA23DAE41AULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0xC8D92241513E350DULL + 0xE0421D64ED995ACFULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseC(pNonce * 0xEBDBFDD1902208C7ULL + 0x85F9AB823ED83A2DULL);
