    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0xA67019E2CD8E38E7ULL + 0x8D6C78992718D68BULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0xE90F883B3B597D4FULL + 0x9B2D237FEA86DE41ULL);
