            //
            aOrbiterG = (aOrbiterG + aOrbiterI) + 12071156696202511606U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 12772646124613086448U;
            aOrbiterJ = RotL64((aOrbiterJ * 15196500821088842155U), 3U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 16613754887273466292U;
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 8808647481066662030U;
            aOrbiterH = RotL64((aOrbiterH * 4376613874096307531U), 19U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterJ) + 17325640359364363595U;
            aOrbiterE = (aOrbiterE ^ aOrbiterH) ^ 13382596494088288943U;
            aOrbiterE = RotL64((aOrbiterE * 3946678879632775019U), 35U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 16271773947851197336U;
            aOrbiterI = ((aOrbiterI ^ aOrbiterC) ^ 11230509324740125583U) ^ aNonceWordD;
