            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterA) + 3537657382540215615U) + aOrbiterUpdateSaltB[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterJ) ^ 11805235230102679224U;
            aOrbiterC = RotL64((aOrbiterC * 4784097066516518397U), 5U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterE) + 11202056839935778951U;
            aOrbiterF = ((aOrbiterF ^ aOrbiterD) ^ 379951957880315839U) ^ aNonceWordL;
            aOrbiterF = RotL64((aOrbiterF * 10505372602243849997U), 39U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterH) + 8204699116748424699U;
