            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererF = aWandererF ^ ((RotL64(aScatter, 27U) + RotL64(aOrbiterA, 39U)) + aOrbiterD);
            aWandererE = aWandererE + ((RotL64(aIngress, 3U) + aOrbiterA) + RotL64(aOrbiterG, 41U));
